pub(super) fn builder_error_to_backend(e: BuilderError) -> BackendError {
    match e {
        BuilderError::InsufficientFunds { available, required } =>
            BackendError::InsufficientFunds { available, required },
        BuilderError::CoinSelection(SelectionError::InsufficientFunds { available, required }) =>
            BackendError::InsufficientFunds { available, required },
        other => BackendError::Internal(other.to_string()),
    }
}
